import java.util.Scanner;

public class SecureBufferExample {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String input = scanner.nextLine();

        // Validate input length before copying
        if (input.length() > 10) {
            System.out.println("Input exceeds buffer size limit. Please enter a shorter name.");
            return;
        }

        byte[] buffer = new byte[10];
        byte[] inputBytes = input.getBytes();

        // Copy input into buffer
        System.arraycopy(inputBytes, 0, buffer, 0, Math.min(inputBytes.length, buffer.length));

        // Print the sanitized output
        System.out.println("Hello, " + new String(buffer).trim());
    }
}

### Explanation:
취약유형: Buffer Overflow
